1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const BLOCK_SIZE = 3;
9	const BLOCK_PREMIUM = 60;
10	
11	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Step = QuoteStep;
14	type Customer = { yearsWithMHPCO: number };
15	type Scenario = { customer: Customer; steps: Step[] };
16	
17	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
18	
19	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
20	  sword: { basePremium: 100, isComponent: false },
21	  amulet: { basePremium: 60, isComponent: false },
22	  staff: { basePremium: 80, isComponent: false },
23	  potion: { basePremium: 40, isComponent: false },
24	  rune: { basePremium: 25, isComponent: true },
25	  moonstone: { basePremium: 25, isComponent: true },
26	};
27	
28	const basePremiumFor = (item: Item): number => ITEM_TYPES[item.type].basePremium;
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const premiumForTypeCount = (type: string, count: number): number => {
39	  const spec = ITEM_TYPES[type];
40	  return spec.isComponent && count === BLOCK_SIZE
41	    ? BLOCK_PREMIUM
42	    : count * spec.basePremium;
43	};
44	
45	const basePremiumOf = (items: Item[]): number => {
46	  let total = 0;
47	  for (const [type, count] of countByType(items)) {
48	    total += premiumForTypeCount(type, count);
49	  }
50	  return total;
51	};
52	
53	const curseSurchargeFor = (item: Item): number =>
54	  item.cursed ? basePremiumFor(item) * CURSE_SURCHARGE_RATE : 0;
55	
56	const highEnchantmentSurchargeFor = (item: Item): number =>
57	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
58	    ? basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
59	    : 0;
60	
61	const itemSurchargesOf = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + curseSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
63	
64	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
65	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
66	    ? basePremium * LOYALTY_DISCOUNT_RATE
67	    : 0;
68	
69	const quoteForStep = ({ items }: QuoteStep, customer: Customer) => {
70	  const basePremium = basePremiumOf(items);
71	  const itemSurcharges = itemSurchargesOf(items);
72	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
73	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
74	  return {
75	    premium: Math.ceil(
76	      basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
77	    ),
78	  };
79	};
80	
81	export const runScenario = (scenario: Scenario): unknown => {
82	  return { results: scenario.steps.map((step) => quoteForStep(step, scenario.customer)) };
83	};
